// Reference implementation for Pocket - Verify HMAC & Dedup (n8n Code node v2).
// Pure JS HMAC-SHA256 (require('crypto') and Web Crypto are blocked in n8n sandbox).
// Raw body: with Webhook "Raw Body" enabled, n8n puts the exact payload in binary.data (base64).

function envGet(key) {
  try {
    return $env[key];
  } catch (e) {
    return undefined;
  }
}

function timingSafeEqual(a, b) {
  if (a.length !== b.length) return false;
  let out = 0;
  for (let i = 0; i < a.length; i++) out |= a.charCodeAt(i) ^ b.charCodeAt(i);
  return out === 0;
}

function bytesToHex(bytes) {
  return Array.from(bytes).map((b) => b.toString(16).padStart(2, '0')).join('');
}

function bytesToBase64(bytes) {
  if (typeof Buffer !== 'undefined') {
    return Buffer.from(bytes).toString('base64');
  }
  let binary = '';
  for (const b of bytes) binary += String.fromCharCode(b);
  return btoa(binary);
}

function utf8Bytes(str) {
  if (typeof TextEncoder !== 'undefined') {
    return new TextEncoder().encode(str);
  }
  if (typeof Buffer !== 'undefined') {
    return Uint8Array.from(Buffer.from(str, 'utf8'));
  }
  const out = [];
  for (let i = 0; i < str.length; i++) {
    let c = str.charCodeAt(i);
    if (c < 0x80) out.push(c);
    else if (c < 0x800) {
      out.push(0xc0 | (c >> 6), 0x80 | (c & 0x3f));
    } else if (c >= 0xd800 && c <= 0xdbff && i + 1 < str.length) {
      const c2 = str.charCodeAt(++i);
      const u = 0x10000 + ((c - 0xd800) << 10) + (c2 - 0xdc00);
      out.push(
        0xf0 | (u >> 18),
        0x80 | ((u >> 12) & 0x3f),
        0x80 | ((u >> 6) & 0x3f),
        0x80 | (u & 0x3f)
      );
    } else {
      out.push(0xe0 | (c >> 12), 0x80 | ((c >> 6) & 0x3f), 0x80 | (c & 0x3f));
    }
  }
  return new Uint8Array(out);
}

function decodeRawBody(input) {
  const bin = input.binary && input.binary.data;
  if (bin && bin.data) {
    if (typeof Buffer !== 'undefined') {
      return Buffer.from(bin.data, 'base64').toString('utf8');
    }
    const bytes = Uint8Array.from(atob(bin.data), (c) => c.charCodeAt(0));
    if (typeof TextDecoder !== 'undefined') {
      return new TextDecoder().decode(bytes);
    }
    if (typeof Buffer !== 'undefined') {
      return Buffer.from(bytes).toString('utf8');
    }
    throw new Error('Cannot decode webhook raw body (no Buffer/TextDecoder).');
  }
  const item = input.json || {};
  if (item.rawBody != null) return String(item.rawBody);
  if (typeof item.body === 'string') return item.body;
  if (item.body !== undefined) return JSON.stringify(item.body);
  return null;
}

// --- SHA-256 (pure JS) ---
const K = new Uint32Array([
  0x428a2f98, 0x71374491, 0xb5c0fbcf, 0xe9b5dba5, 0x3956c25b, 0x59f111f1, 0x923f82a4, 0xab1c5ed5,
  0xd807aa98, 0x12835b01, 0x243185be, 0x550c7dc3, 0x72be5d74, 0x80deb1fe, 0x9bdc06a7, 0xc19bf174,
  0xe49b69c1, 0xefbe4786, 0x0fc19dc6, 0x240ca1cc, 0x2de92c6f, 0x4a7484aa, 0x5cb0a9dc, 0x76f988da,
  0x983e5152, 0xa831c66d, 0xb00327c8, 0xbf597fc7, 0xc6e00bf3, 0xd5a79147, 0x06ca6351, 0x14292967,
  0x27b70a85, 0x2e1b2138, 0x4d2c6dfc, 0x53380d13, 0x650a7354, 0x766a0abb, 0x81c2c92e, 0x92722c85,
  0xa2bfe8a1, 0xa81a664b, 0xc24b8b70, 0xc76c51a3, 0xd192e819, 0xd6990624, 0xf40e3585, 0x106aa070,
  0x19a4c116, 0x1e376c08, 0x2748774c, 0x34b0bcb5, 0x391c0cb3, 0x4ed8aa4a, 0x5b9cca4f, 0x682e6ff3,
  0x748f82ee, 0x78a5636f, 0x84c87814, 0x8cc70208, 0x90befffa, 0xa4506ceb, 0xbef9a3f7, 0xc67178f2,
]);

function rotr(x, n) {
  return (x >>> n) | (x << (32 - n));
}

function sha256Bytes(data) {
  const l = data.length;
  const bitLen = l * 8;
  const withOne = l + 1;
  const padLen = (withOne % 64 <= 56 ? 56 : 120) - (withOne % 64) + withOne;
  const buf = new Uint8Array(padLen + 8);
  buf.set(data);
  buf[l] = 0x80;
  const view = new DataView(buf.buffer);
  view.setUint32(buf.length - 4, bitLen, false);

  let h0 = 0x6a09e667;
  let h1 = 0xbb67ae85;
  let h2 = 0x3c6ef372;
  let h3 = 0xa54ff53a;
  let h4 = 0x510e527f;
  let h5 = 0x9b05688c;
  let h6 = 0x1f83d9ab;
  let h7 = 0x5be0cd19;

  const w = new Uint32Array(64);
  for (let i = 0; i < buf.length; i += 64) {
    for (let t = 0; t < 16; t++) {
      w[t] = view.getUint32(i + t * 4, false);
    }
    for (let t = 16; t < 64; t++) {
      const s0 = rotr(w[t - 15], 7) ^ rotr(w[t - 15], 18) ^ (w[t - 15] >>> 3);
      const s1 = rotr(w[t - 2], 17) ^ rotr(w[t - 2], 19) ^ (w[t - 2] >>> 10);
      w[t] = (w[t - 16] + s0 + w[t - 7] + s1) >>> 0;
    }
    let a = h0;
    let b = h1;
    let c = h2;
    let d = h3;
    let e = h4;
    let f = h5;
    let g = h6;
    let hh = h7;
    for (let t = 0; t < 64; t++) {
      const S1 = rotr(e, 6) ^ rotr(e, 11) ^ rotr(e, 25);
      const ch = (e & f) ^ (~e & g);
      const temp1 = (hh + S1 + ch + K[t] + w[t]) >>> 0;
      const S0 = rotr(a, 2) ^ rotr(a, 13) ^ rotr(a, 22);
      const maj = (a & b) ^ (a & c) ^ (b & c);
      const temp2 = (S0 + maj) >>> 0;
      hh = g;
      g = f;
      f = e;
      e = (d + temp1) >>> 0;
      d = c;
      c = b;
      b = a;
      a = (temp1 + temp2) >>> 0;
    }
    h0 = (h0 + a) >>> 0;
    h1 = (h1 + b) >>> 0;
    h2 = (h2 + c) >>> 0;
    h3 = (h3 + d) >>> 0;
    h4 = (h4 + e) >>> 0;
    h5 = (h5 + f) >>> 0;
    h6 = (h6 + g) >>> 0;
    h7 = (h7 + hh) >>> 0;
  }

  const out = new Uint8Array(32);
  const outView = new DataView(out.buffer);
  outView.setUint32(0, h0, false);
  outView.setUint32(4, h1, false);
  outView.setUint32(8, h2, false);
  outView.setUint32(12, h3, false);
  outView.setUint32(16, h4, false);
  outView.setUint32(20, h5, false);
  outView.setUint32(24, h6, false);
  outView.setUint32(28, h7, false);
  return out;
}

function hmacSha256(keyStr, msgStr) {
  const block = 64;
  let key = utf8Bytes(keyStr);
  if (key.length > block) key = sha256Bytes(key);
  if (key.length < block) {
    const padded = new Uint8Array(block);
    padded.set(key);
    key = padded;
  }
  const iKeyPad = new Uint8Array(block);
  const oKeyPad = new Uint8Array(block);
  for (let i = 0; i < block; i++) {
    iKeyPad[i] = key[i] ^ 0x36;
    oKeyPad[i] = key[i] ^ 0x5c;
  }
  const msg = utf8Bytes(msgStr);
  const inner = new Uint8Array(block + msg.length);
  inner.set(iKeyPad);
  inner.set(msg, block);
  const innerHash = sha256Bytes(inner);
  const outer = new Uint8Array(block + innerHash.length);
  outer.set(oKeyPad);
  outer.set(innerHash, block);
  return sha256Bytes(outer);
}

const FALLBACK_SECRET = 'dev-pocket-signing-secret';
const secret = envGet('POCKET_WEBHOOK_SIGNING_SECRET') || FALLBACK_SECRET;
if (!secret || secret === 'REPLACE_POCKET_WEBHOOK_SIGNING_SECRET') {
  throw new Error('POCKET_WEBHOOK_SIGNING_SECRET not configured (set n8n env var or update Code node fallback constant).');
}

const input = $input.first();
const item = input.json || {};
const headers = Object.fromEntries(
  Object.entries(item.headers || {}).map(([k, v]) => [String(k).toLowerCase(), v])
);

const timestamp = headers['x-heypocket-timestamp'];
const signature = headers['x-heypocket-signature'];
if (!timestamp || !signature) {
  throw new Error('Missing X-HeyPocket-Timestamp or X-HeyPocket-Signature headers.');
}

const rawBody = decodeRawBody(input);
if (rawBody == null) {
  throw new Error('Missing raw body for Pocket HMAC verification.');
}

const timestampRaw = String(timestamp).trim();
let tsSeconds = parseInt(timestampRaw, 10);
if (Number.isNaN(tsSeconds)) {
  throw new Error('Invalid X-HeyPocket-Timestamp.');
}
// Pocket docs: X-HeyPocket-Timestamp is Unix time in milliseconds.
if (timestampRaw.length >= 13 || tsSeconds > 1e12) {
  tsSeconds = Math.floor(tsSeconds / 1000);
}
const now = Math.floor(Date.now() / 1000);
const SKEW_SECONDS = 300;
if (Math.abs(now - tsSeconds) > SKEW_SECONDS) {
  throw new Error(`Pocket webhook timestamp outside allowed window (${SKEW_SECONDS / 60} minutes).`);
}

// HMAC uses the exact header string Pocket sent (typically ms).
const signedPayload = `${timestampRaw}.${rawBody}`;
const mac = hmacSha256(secret, signedPayload);
const expectedHex = bytesToHex(mac);
const expectedB64 = bytesToBase64(mac);
const provided = String(signature).replace(/^sha256=/, '');

if (!timingSafeEqual(expectedHex, provided) && !timingSafeEqual(expectedB64, provided)) {
  const usingFallback = !envGet('POCKET_WEBHOOK_SIGNING_SECRET');
  throw new Error(
    usingFallback
      ? 'Invalid Pocket webhook HMAC signature. POCKET_WEBHOOK_SIGNING_SECRET is not set on the n8n container — restart n8n after adding it to .env, or update FALLBACK_SECRET in this Code node to match Pocket.'
      : 'Invalid Pocket webhook HMAC signature. Confirm POCKET_WEBHOOK_SIGNING_SECRET matches the signing secret shown when you created the Pocket webhook.'
  );
}

const body = typeof item.body === 'object' && item.body !== null ? item.body : JSON.parse(rawBody);

function extractRecordingId(payload) {
  if (!payload || typeof payload !== 'object') return null;
  if (payload.recording && payload.recording.id) return payload.recording.id;
  const data = payload.data || payload;
  return data.recording_id || data.recordingId || data.id || null;
}

const recordingId = extractRecordingId(body);
if (!recordingId) {
  throw new Error('Missing recording_id in Pocket webhook payload.');
}

const event = body.event || body.type || 'summary.completed';
const deliveryKey = body.id || body.delivery_id || body.event_id || body.timestamp || `${event}:${timestampRaw}`;
const dedupKey = `${recordingId}:${deliveryKey}`;

const staticData = $getWorkflowStaticData('global');
if (!staticData.seenEvents) staticData.seenEvents = {};
if (!staticData.seenEventKeys) staticData.seenEventKeys = [];

const existing = staticData.seenEvents[dedupKey];
if (existing) {
  return [{
    json: {
      duplicate: true,
      job_id: existing.job_id,
      recording_id: recordingId,
      event,
      dedup_key: dedupKey,
    },
  }];
}

const jobId = `${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;

staticData.seenEvents[dedupKey] = { job_id: jobId, handled_at: new Date().toISOString() };
staticData.seenEventKeys.push(dedupKey);
const MAX = 500;
while (staticData.seenEventKeys.length > MAX) {
  const old = staticData.seenEventKeys.shift();
  delete staticData.seenEvents[old];
}

return [{
  json: {
    duplicate: false,
    job_id: jobId,
    recording_id: recordingId,
    event,
    dedup_key: dedupKey,
    raw: body,
  },
}];

const response = $json || {};
const rec = response.data || response;
const meta = $('Pocket - Verify HMAC & Dedup').first().json;

let transcript = null;
if (typeof rec.transcript === 'string') transcript = rec.transcript;
else if (rec.transcript && rec.transcript.text) transcript = rec.transcript.text;
else if (rec.transcription && rec.transcription.text) transcript = rec.transcription.text;

let summary = null;
if (typeof rec.summary === 'string') summary = rec.summary;
else if (rec.summary && rec.summary.text) summary = rec.summary.text;
else if (Array.isArray(rec.summarizations) && rec.summarizations.length) {
  const s0 = rec.summarizations[0];
  summary = typeof s0 === 'string' ? s0 : (s0.text || s0.summary || null);
} else if (rec.summarization && rec.summarization.text) {
  summary = rec.summarization.text;
}

const payload = {
  source: 'pocket',
  job_id: meta.job_id,
  recording_id: meta.recording_id,
  title: rec.title || rec.name || null,
  created_at: rec.created_at || rec.createdAt || null,
  transcript,
  summary,
  action_items: rec.action_items || rec.actionItems || [],
  mind_map_available: Boolean(rec.mind_map || rec.mindMap || rec.mind_map_available),
  tags: rec.tags || [],
  audio_url_if_needed: rec.audio_url || rec.audioUrl || null,
  intent_status: 'needs_user_decision',
  event: meta.event,
  dedup_key: meta.dedup_key
};

return [{ json: payload }];
